diffs.replacement:
import React, { useState } from 'react';
import { useAppStore } from '../../services/store';
import { Assignment } from '../../types';
import { generateAssignmentIdeas, generateFeedbackHelper } from '../../services/geminiService';
import { Sparkles, Send, CheckCircle, Clock, PenTool, Save, Download, Bell, MessageSquare, GraduationCap, X } from 'lucide-react';

interface Props {
  activeTab: string;
}

const TeacherView: React.FC<Props> = ({ activeTab }) => {
  const { state, dispatch } = useAppStore();
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState('');

  // Form State
  const [newAssignment, setNewAssignment] = useState({
    title: '',
    description: '',
    subject: state.currentUser?.subjects?.[0] || '',
    targetClassId: '12',
    dueDate: '',
  });

  // Grading View State
  const [gradingAssignmentId, setGradingAssignmentId] = useState('');

  // Marks Entry State
  const [selectedSessionId, setSelectedSessionId] = useState('');
  const [selectedClassId, setSelectedClassId] = useState('');
  const [selectedSection, setSelectedSection] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('');

  // Marks Config defaults
  const [fullMarks, setFullMarks] = useState(100);
  const [passMarks, setPassMarks] = useState(40);

  const handleCreateAssignment = (e: React.FormEvent) => {
    e.preventDefault();
    const assignment: Assignment = {
      id: Date.now().toString(),
      ...newAssignment,
      teacherId: state.currentUser?.id || '',
      createdAt: new Date().toISOString().split('T')[0],
    };
    dispatch({ type: 'ADD_ASSIGNMENT', payload: assignment });
    setShowCreateModal(false);
  };

  const handleAiAssist = async () => {
    if (!newAssignment.subject) return;
    setAiLoading(true);
    const ideas = await generateAssignmentIdeas(newAssignment.subject, "General Topic");
    setAiSuggestion(ideas);
    setAiLoading(false);
  };

  // Grading State
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [gradeData, setGradeData] = useState({ grade: '', feedback: '' });
  const [gradingLoading, setGradingLoading] = useState(false);

  const handleAiFeedback = async (submissionContent: string, assignmentId: string) => {
      const assignment = state.assignments.find(a => a.id === assignmentId);
      if(!assignment) return;
      setGradingLoading(true);
      const feedback = await generateFeedbackHelper(submissionContent, assignment.description);
      setGradeData(prev => ({ ...prev, feedback }));
      setGradingLoading(false);
  }

  const submitGrade = () => {
      if(selectedSubmissionId) {
          dispatch({
              type: 'GRADE_SUBMISSION',
              payload: { id: selectedSubmissionId, ...gradeData }
          });
          setSelectedSubmissionId(null);
          setGradeData({ grade: '', feedback: '' });
      }
  }

  // Marks Entry Handlers
  const handleScoreChange = (studentId: string, scoreStr: string) => {
      if (!selectedSessionId || !selectedSubject) return;
      const score = parseFloat(scoreStr);
      if (isNaN(score)) return;

      const session = state.examSessions.find(s => s.id === selectedSessionId);

      dispatch({
          type: 'UPDATE_EXAM_MARKS',
          payload: {
              studentId,
              examSessionId: selectedSessionId,
              sessionName: session?.name || '',
              subject: selectedSubject,
              scoreData: {
                  obtained: score,
                  fullMarks,
                  passMarks
              }
          }
      });
  };

  const exportToCSV = (filteredStudents: any[]) => {
      if (filteredStudents.length === 0) return;

      const csvRows = [
          ['Student Name', 'Section', 'Subject', 'Full Marks', 'Pass Marks', 'Obtained Marks']
      ];

      filteredStudents.forEach(student => {
          const report = state.examReports.find(r => r.studentId === student.id && r.examSessionId === selectedSessionId);
          const data = report?.scores[selectedSubject];
          csvRows.push([
              student.name,
              student.section || '-',
              selectedSubject,
              data?.fullMarks?.toString() || fullMarks.toString(),
              data?.passMarks?.toString() || passMarks.toString(),
              data?.obtained?.toString() || '0'
          ]);
      });

      const csvContent = "data:text/csv;charset=utf-8," + csvRows.map(e => e.join(",")).join("\n");
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `${selectedSubject}_Marks_${selectedClassId}.csv`);
      document.body.appendChild(link);
      link.click();
  }

  const selectedClassData = state.systemClasses.find(c => c.name === selectedClassId);

  if (activeTab === 'marks_entry') {
      const openSessions = state.examSessions.filter(s => s.status === 'open');
      const uniqueClasses = state.systemClasses.map(c => c.name);

      const filteredStudents = selectedClassId 
          ? state.users.filter(u => {
              const isStudent = u.role === 'student';
              const matchesClass = u.classId === selectedClassId;
              const matchesSection = !selectedSection || u.section === selectedSection;
              return isStudent && matchesClass && matchesSection;
          })
          : [];

      return (
          <div className="space-y-6">
              <div className="bg-white p-4 md:p-6 rounded-xl border shadow-sm">
                  <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                      <PenTool className="text-galaxy-600" /> Exam Marks Entry
                  </h3>

                  {openSessions.length === 0 ? (
                      <div className="text-center p-8 bg-gray-50 rounded-lg text-gray-500">
                          No exams are currently open for marks entry. Please contact the admin.
                      </div>
                  ) : (
                      <div className="space-y-6">
                          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                              <div>
                                  <label className="block text-sm font-bold text-gray-700 mb-1">Select Exam Session</label>
                                  <select 
                                      className="w-full border p-2 rounded"
                                      value={selectedSessionId}
                                      onChange={e => setSelectedSessionId(e.target.value)}
                                  >
                                      <option value="">-- Choose Exam --</option>
                                      {openSessions.map(s => <option key={s.id} value={s.id}>{s.name} ({s.type})</option>)}
                                  </select>
                              </div>
                              <div>
                                  <label className="block text-sm font-bold text-gray-700 mb-1">Select Class</label>
                                  <select 
                                      className="w-full border p-2 rounded"
                                      value={selectedClassId}
                                      onChange={e => { setSelectedClassId(e.target.value); setSelectedSection(''); }}
                                  >
                                      <option value="">-- Choose Class --</option>
                                      {uniqueClasses.map(c => <option key={c} value={c}>{c}</option>)}
                                  </select>
                              </div>
                              <div>
                                  <label className="block text-sm font-bold text-gray-700 mb-1">Select Section</label>
                                  <select 
                                      className="w-full border p-2 rounded"
                                      value={selectedSection}
                                      onChange={e => setSelectedSection(e.target.value)}
                                      disabled={!selectedClassData || selectedClassData.sections.length === 0}
                                  >
                                      <option value="">All Sections</option>
                                      {selectedClassData?.sections.map(s => <option key={s} value={s}>{s}</option>)}
                                  </select>
                              </div>
                              <div>
                                  <label className="block text-sm font-bold text-gray-700 mb-1">Select Subject</label>
                                  <select 
                                      className="w-full border p-2 rounded"
                                      value={selectedSubject}
                                      onChange={e => setSelectedSubject(e.target.value)}
                                  >
                                      <option value="">-- Choose Subject --</option>
                                      {state.currentUser?.subjects?.map(s => <option key={s} value={s}>{s}</option>)}
                                  </select>
                              </div>
                          </div>

                          {selectedSessionId && selectedClassId && selectedSubject && (
                              <div className="flex flex-col md:flex-row gap-4 p-4 bg-gray-50 border rounded-lg items-end">
                                  <div className="w-full md:w-auto">
                                      <label className="block text-xs font-bold text-gray-500 uppercase">Full Marks</label>
                                      <input type="number" value={fullMarks} onChange={e => setFullMarks(Number(e.target.value))} className="border p-2 rounded w-full md:w-24" />
                                  </div>
                                  <div className="w-full md:w-auto">
                                      <label className="block text-xs font-bold text-gray-500 uppercase">Pass Marks</label>
                                      <input type="number" value={passMarks} onChange={e => setPassMarks(Number(e.target.value))} className="border p-2 rounded w-full md:w-24" />
                                  </div>
                                  <div className="flex-1 text-right w-full md:w-auto">
                                      <button 
                                        onClick={() => exportToCSV(filteredStudents)}
                                        className="bg-green-600 text-white px-3 py-2 rounded flex items-center justify-center gap-2 w-full md:w-auto md:ml-auto hover:bg-green-700"
                                      >
                                          <Download size={16} /> Export to CSV
                                      </button>
                                  </div>
                              </div>
                          )}

                          {selectedSessionId && selectedClassId && selectedSubject ? (
                              <div className="mt-6">
                                  <div className="border rounded-lg overflow-hidden">
                                      <table className="w-full text-left table-fixed md:table-auto">
                                          <thead className="bg-gray-50 text-gray-700">
                                              <tr>
                                                  <th className="p-3 text-sm font-bold">Student Name</th>
                                                  <th className="p-3 text-sm font-bold hidden md:table-cell">Section</th>
                                                  <th className="p-3 w-28 md:w-32 text-right text-sm font-bold">Marks</th>
                                              </tr>
                                          </thead>
                                          <tbody className="divide-y bg-white">
                                              {filteredStudents.map(student => {
                                                  const report = state.examReports.find(
                                                      r => r.studentId === student.id && r.examSessionId === selectedSessionId
                                                  );
                                                  const scoreData = report?.scores[selectedSubject];
                                                  const score = scoreData ? scoreData.obtained : '';

                                                  return (
                                                      <tr key={student.id}>
                                                          <td className="p-3">
                                                              <div className="font-medium text-gray-900 truncate">{student.name}</div>
                                                              <div className="text-[10px] text-gray-400 md:hidden uppercase tracking-wider">{student.section || '-'}</div>
                                                          </td>
                                                          <td className="p-3 text-sm text-gray-500 hidden md:table-cell">{student.section || '-'}</td>
                                                          <td className="p-3 text-right">
                                                              <input 
                                                                  type="number" 
                                                                  className="border p-2 rounded w-20 md:w-24 text-right font-mono focus:ring-2 focus:ring-galaxy-500 outline-none"
                                                                  placeholder="0"
                                                                  value={score}
                                                                  onChange={e => handleScoreChange(student.id, e.target.value)}
                                                              />
                                                          </td>
                                                      </tr>
                                                  );
                                              })}
                                          </tbody>
                                      </table>
                                      {filteredStudents.length === 0 && (
                                          <div className="p-4 text-center text-gray-500">No students found in this class/section.</div>
                                      )}
                                  </div>
                              </div>
                          ) : (
                              <div className="p-8 text-center bg-gray-50 border-2 border-dashed border-gray-200 rounded-lg text-gray-400">
                                  Please select Exam, Class, and Subject to start entering marks.
                              </div>
                          )}
                      </div>
                  )}
              </div>
          </div>
      );
  }

  // Submissions & Grading Tab
  if (activeTab === 'submissions') {
      const myAssignments = state.assignments.filter(a => a.teacherId === state.currentUser?.id);
      const submissionsForSelected = state.submissions.filter(s => s.assignmentId === gradingAssignmentId);

      return (
          <div className="space-y-6">
              <h3 className="text-xl font-bold flex items-center gap-2">
                  <GraduationCap className="text-galaxy-600" /> Submissions & Grading
              </h3>

              {/* Assignment Selector */}
              <div className="bg-white p-4 rounded-xl border shadow-sm">
                  <label className="block text-sm font-bold text-gray-700 mb-1">Select Assignment to Grade</label>
                  <select 
                      className="w-full border p-2 rounded-lg"
                      value={gradingAssignmentId}
                      onChange={e => setGradingAssignmentId(e.target.value)}
                  >
                      <option value="">-- Choose Assignment --</option>
                      {myAssignments.map(a => (
                          <option key={a.id} value={a.id}>
                              {a.title} ({a.targetClassId}) - Due: {a.dueDate}
                          </option>
                      ))}
                  </select>
              </div>

              {gradingAssignmentId ? (
                  <div className="space-y-4">
                      {submissionsForSelected.length === 0 ? (
                          <div className="p-8 text-center bg-gray-50 border-2 border-dashed rounded-lg text-gray-500">
                              No submissions received for this assignment yet.
                          </div>
                      ) : (
                          submissionsForSelected.map(submission => {
                              const isEditing = selectedSubmissionId === submission.id;

                              return (
                                  <div key={submission.id} className="bg-white border rounded-xl overflow-hidden shadow-sm">
                                      <div className="bg-gray-50 p-4 border-b flex justify-between items-center">
                                          <div>
                                              <p className="font-bold text-lg text-gray-800">{submission.studentName}</p>
                                              <p className="text-xs text-gray-500 flex items-center gap-1">
                                                  <Clock size={12}/> Submitted: {submission.submittedAt}
                                              </p>
                                          </div>
                                          {!isEditing && (
                                              <div className="flex items-center gap-3">
                                                  {submission.grade ? (
                                                      <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-sm font-bold border border-green-200">
                                                          Grade: {submission.grade}
                                                      </span>
                                                  ) : (
                                                      <span className="bg-amber-100 text-amber-700 px-3 py-1 rounded-full text-sm font-bold border border-amber-200">
                                                          Pending
                                                      </span>
                                                  )}
                                                  <button 
                                                      onClick={() => {
                                                          setSelectedSubmissionId(submission.id);
                                                          setGradeData({ grade: submission.grade || '', feedback: submission.feedback || '' });
                                                      }}
                                                      className="text-galaxy-600 hover:underline text-sm font-medium"
                                                  >
                                                      {submission.grade ? 'Edit Grade' : 'Grade Now'}
                                                  </button>
                                              </div>
                                          )}
                                      </div>

                                      <div className="p-6">
                                          <div className="mb-4">
                                              <h5 className="text-xs font-bold text-gray-400 uppercase mb-1">Student Answer</h5>
                                              <p className="text-gray-800 bg-gray-50 p-4 rounded-lg border border-gray-100 whitespace-pre-wrap">
                                                  {submission.content}
                                              </p>
                                          </div>

                                          {isEditing ? (
                                              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 animate-in fade-in">
                                                  <h5 className="text-sm font-bold text-blue-900 mb-3 flex items-center gap-2">
                                                      <PenTool size={16}/> Grading Console
                                                  </h5>
                                                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                                                      <div>
                                                          <label className="block text-xs font-bold text-gray-600 uppercase mb-1">Grade / Score</label>
                                                          <input 
                                                              type="text" 
                                                              className="w-full border p-2 rounded bg-white"
                                                              placeholder="e.g. A, 85/100"
                                                              value={gradeData.grade}
                                                              onChange={e => setGradeData({...gradeData, grade: e.target.value})}
                                                          />
                                                      </div>
                                                      <div className="md:col-span-2">
                                                           <label className="block text-xs font-bold text-gray-600 uppercase mb-1">Feedback</label>
                                                           <div className="relative">
                                                               <textarea 
                                                                  className="w-full border p-2 rounded bg-white h-24"
                                                                  placeholder="Enter constructive feedback..."
                                                                  value={gradeData.feedback}
                                                                  onChange={e => setGradeData({...gradeData, feedback: e.target.value})}
                                                               />
                                                               <button 
                                                                  onClick={() => handleAiFeedback(submission.content, gradingAssignmentId)}
                                                                  disabled={gradingLoading}
                                                                  className="absolute bottom-2 right-2 text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded hover:bg-purple-200 flex items-center gap-1 border border-purple-200"
                                                               >
                                                                   <Sparkles size={12} /> {gradingLoading ? 'Generating...' : 'Auto-Generate'}
                                                               </button>
                                                           </div>
                                                      </div>
                                                  </div>
                                                  <div className="flex gap-2 justify-end">
                                                      <button 
                                                          onClick={() => setSelectedSubmissionId(null)}
                                                          className="px-4 py-2 text-gray-600 hover:bg-gray-200 rounded"
                                                      >
                                                          Cancel
                                                      </button>
                                                      <button 
                                                          onClick={submitGrade}
                                                          className="px-4 py-2 bg-galaxy-600 text-white rounded hover:bg-galaxy-700 flex items-center gap-2"
                                                      >
                                                          <Save size={16} /> Save Grading
                                                      </button>
                                                  </div>
                                              </div>
                                          ) : (
                                              submission.feedback && (
                                                  <div className="mt-4 border-t pt-4">
                                                      <h5 className="text-xs font-bold text-gray-400 uppercase mb-1">Teacher Feedback</h5>
                                                      <p className="text-gray-700 italic flex items-start gap-2">
                                                          <MessageSquare size={16} className="text-gray-400 mt-1 shrink-0" />
                                                          "{submission.feedback}"
                                                      </p>
                                                  </div>
                                              )
                                          )}
                                      </div>
                                  </div>
                              );
                          })
                      )}
                  </div>
              ) : (
                  <div className="flex flex-col items-center justify-center h-64 bg-gray-50 border-2 border-dashed border-gray-200 rounded-xl">
                      <div className="p-4 bg-white rounded-full shadow-sm mb-4 text-gray-400">
                          <GraduationCap size={32} />
                      </div>
                      <p className="text-gray-500 font-medium">Please select an assignment above to view submissions.</p>
                  </div>
              )}
          </div>
      );
  }

  // Fallback for assignments/notices (Existing Code)
  if (activeTab === 'assignments') {
    return (
      <div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-semibold text-gray-700">Current Assignments</h3>
          <button 
            onClick={() => setShowCreateModal(true)}
            className="bg-galaxy-600 text-white px-4 py-2 rounded-lg hover:bg-galaxy-700 transition"
          >
            + New Assignment
          </button>
        </div>

        {showCreateModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white p-6 rounded-xl w-full max-w-2xl">
              <div className="flex justify-between mb-4">
                 <h3 className="text-xl font-bold">Create Assignment</h3>
                 <button onClick={() => setShowCreateModal(false)} className="text-gray-500">Close</button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <form onSubmit={handleCreateAssignment} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Subject</label>
                        <select 
                            value={newAssignment.subject}
                            onChange={e => setNewAssignment({...newAssignment, subject: e.target.value})}
                            className="w-full border rounded-md p-2 mt-1"
                        >
                            {state.currentUser?.subjects?.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Target Class</label>
                        <input 
                            type="text" 
                            value={newAssignment.targetClassId}
                            onChange={e => setNewAssignment({...newAssignment, targetClassId: e.target.value})}
                            className="w-full border rounded-md p-2 mt-1"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Title</label>
                        <input 
                            type="text" 
                            value={newAssignment.title}
                            onChange={e => setNewAssignment({...newAssignment, title: e.target.value})}
                            className="w-full border rounded-md p-2 mt-1"
                            required
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Description</label>
                        <textarea 
                            value={newAssignment.description}
                            onChange={e => setNewAssignment({...newAssignment, description: e.target.value})}
                            className="w-full border rounded-md p-2 mt-1 h-32"
                            required
                        />
                         <div className="mt-2 flex justify-end">
                            <button 
                                type="button"
                                onClick={handleAiAssist}
                                disabled={aiLoading || !newAssignment.subject}
                                className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-800 disabled:opacity-50"
                            >
                                <Sparkles size={14} /> {aiLoading ? 'Thinking...' : 'Get AI Ideas'}
                            </button>
                        </div>
                    </div>
                    {aiSuggestion && (
                         <div className="col-span-2 bg-purple-50 p-3 rounded border border-purple-100 text-sm text-purple-800 whitespace-pre-wrap">
                             {aiSuggestion}
                             <button type="button" onClick={() => setAiSuggestion('')} className="block mt-2 text-xs underline">Clear</button>
                         </div>
                    )}
                    <div className="col-span-2">
                         <label className="block text-sm font-medium text-gray-700">Due Date</label>
                         <input 
                            type="date"
                            value={newAssignment.dueDate}
                            onChange={e => setNewAssignment({...newAssignment, dueDate: e.target.value})}
                            className="w-full border rounded-md p-2 mt-1"
                            required
                         />
                    </div>
                    <button type="submit" className="col-span-2 w-full bg-galaxy-600 text-white py-2 rounded-lg hover:bg-galaxy-700">Publish Assignment</button>
                  </form>
              </div>
            </div>
          </div>
        )}
        <div className="space-y-4">
            {state.assignments.filter(a => a.teacherId === state.currentUser?.id).length === 0 ? (
                <div className="text-center p-8 text-gray-500">You haven't created any assignments yet.</div>
            ) : (
                state.assignments.filter(a => a.teacherId === state.currentUser?.id).map(assignment => (
                    <div key={assignment.id} className="border p-4 rounded-lg bg-white shadow-sm flex justify-between items-center">
                        <div>
                            <h4 className="font-bold text-lg">{assignment.title}</h4>
                            <p className="text-sm text-gray-600">{assignment.targetClassId} • {assignment.subject}</p>
                            <p className="text-xs text-red-500 mt-1">Due: {assignment.dueDate}</p>
                        </div>
                        <div className="text-right">
                            <span className="text-xs text-gray-400 block mb-1">Posted: {assignment.createdAt}</span>
                            <div className="text-sm bg-gray-100 px-2 py-1 rounded inline-block">
                                {state.submissions.filter(s => s.assignmentId === assignment.id).length} Submissions
                            </div>
                        </div>
                    </div>
                ))
            )}
        </div>
      </div>
    );
  }

  if (activeTab === 'notices') {
    const relevantNotices = state.notices.filter(n => n.audience === 'all' || n.audience === 'teachers');

    return (
        <div className="space-y-6">
             <h3 className="font-bold text-xl mb-4 flex items-center gap-2">
                 <Bell className="text-galaxy-600" /> Staff Notices
             </h3>
             {relevantNotices.length === 0 ? (
                 <div className="p-8 text-center text-gray-500 bg-white rounded-lg border">No new notices.</div>
             ) : (
                 relevantNotices.map(n => (
                    <div key={n.id} className="bg-white border-l-4 border-purple-500 p-6 rounded-r-lg shadow-sm">
                        <div className="flex justify-between items-start">
                            <h4 className="font-bold text-lg text-galaxy-900">{n.title}</h4>
                            <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">{n.date}</span>
                        </div>
                        <p className="mt-3 text-gray-700 leading-relaxed">{n.content}</p>
                        <div className="mt-4 flex items-center gap-2 text-xs text-gray-400">
                            <span className="font-medium">Posted By:</span> {n.postedBy}
                        </div>
                    </div>
                ))
             )}
        </div>
    )
  }

  return <div className="p-4 text-center text-gray-500">Select a tab.</div>;
};

export default TeacherView;

import React, { useState } from 'react';
import { useAppStore } from '../../services/store';
import { Role, User, ExamType, SubjectType, Notice } from '../../types';
import AccountantView from './AccountantView';
import { Check, X, Printer, Lock, Unlock, AlertTriangle, RefreshCw, UserCheck, Shield, BookOpen, Edit2, Search, Filter, Eye, Settings, Plus, Trash2, Calendar, Layout, ChevronRight, ChevronDown, UploadCloud, Database, ScanFace, LogIn, Briefcase, GraduationCap, Calculator, ChevronLeft, Bell, Send, Users, Clock } from 'lucide-react';
import { INITIAL_STATE } from '../../services/mockData';

interface Props {
  activeTab: string;
  role: Role;
}

const AdminView: React.FC<Props> = ({ activeTab, role }) => {
  const { state, dispatch } = useAppStore();
  const { currentUser } = state;

  // Notice Form
  const [noticeForm, setNoticeForm] = useState({ title: '', content: '', audience: 'all' as 'all' | 'students' | 'teachers' });

  // Search and Filter State
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRole, setFilterRole] = useState<string>('all');

  // Impersonation State
  const [viewMode, setViewMode] = useState<'roles' | 'users'>('roles');
  const [selectedRoleForImp, setSelectedRoleForImp] = useState<Role | null>(null);
  const [impSearch, setImpSearch] = useState('');

  // Approval / Edit Modal State
  const [reviewUser, setReviewUser] = useState<User | null>(null);
  const [reviewData, setReviewData] = useState<Partial<User>>({});

  // System Management State
  const [showSubjectManager, setShowSubjectManager] = useState(false);
  const [newSubject, setNewSubject] = useState('');
  const [newSubjectType, setNewSubjectType] = useState<SubjectType>('Theory');

  const [showClassManager, setShowClassManager] = useState(false);
  const [newClass, setNewClass] = useState('');
  const [newSection, setNewSection] = useState('');
  const [activeClassForSection, setActiveClassForSection] = useState<string | null>(null);

  // Exam Session Form
  const [newSessionName, setNewSessionName] = useState('');
  const [newSessionType, setNewSessionType] = useState<ExamType>('Term Exam');
  const [publishClassId, setPublishClassId] = useState('');
  const [publishSection, setPublishSection] = useState('');

  // Hierarchy Definition
  const roleHierarchy: Record<string, number> = {
    developer: 100,
    admin: 90,
    accountant: 50,
    teacher: 50,
    student: 10,
    intern: 10,
    guest: 0
  };

  const handlePostNotice = (e: React.FormEvent) => {
      e.preventDefault();
      if (!noticeForm.title || !noticeForm.content) return;

      const newNotice: Notice = {
          id: `n${Date.now()}`,
          title: noticeForm.title,
          content: noticeForm.content,
          audience: noticeForm.audience,
          date: new Date().toISOString().split('T')[0],
          postedBy: currentUser?.name || 'Administrator'
      };

      dispatch({ type: 'ADD_NOTICE', payload: newNotice });
      setNoticeForm({ title: '', content: '', audience: 'all' });
      alert('Notice published successfully to the chosen audience.');
  };

  // Approvals Logic
  const getPendingUsers = () => {
      return state.users.filter(u => u.status === 'pending').filter(u => {
          if (role === 'developer') return u.role === 'admin';
          if (role === 'admin') return u.role === 'accountant' || u.role === 'teacher' || u.role === 'student' || u.role === 'intern';
          return false;
      });
  };

  const openReviewModal = (user: User) => {
      setReviewUser(user);
      setReviewData({ ...user, allowedRoles: user.allowedRoles || [user.role] });
  };

  const confirmApprovalOrEdit = () => {
      if (!reviewUser) return;
      const updates: Partial<User> = { ...reviewData };
      delete updates.status; 

      if (updates.role === 'student') {
          updates.annualFee = Number(updates.annualFee || 0);
          updates.discount = Number(updates.discount || 0);
      }
      if (updates.role !== 'student') {
          delete updates.annualFee; delete updates.discount; delete updates.classId; delete updates.section;
      }
      if (updates.role !== 'teacher') {
          delete updates.subjects;
      }

      if (updates.allowedRoles && updates.role && !updates.allowedRoles.includes(updates.role)) {
          updates.allowedRoles.push(updates.role);
      }

      if (reviewUser.status === 'pending') {
          dispatch({ type: 'APPROVE_USER', payload: { id: reviewUser.id, updates } });
      } else {
          dispatch({ type: 'UPDATE_USER_DETAILS', payload: { id: reviewUser.id, ...updates } });
      }
      setReviewUser(null);
      setReviewData({});
  };

  const handleReject = (id: string) => {
      if(window.confirm('Are you sure you want to reject this registration?')) {
          dispatch({ type: 'REJECT_USER', payload: id });
      }
  };

  const toggleSubjectInReview = (subjectName: string) => {
      const currentSubjects = reviewData.subjects || [];
      if (currentSubjects.includes(subjectName)) {
          setReviewData({ ...reviewData, subjects: currentSubjects.filter(s => s !== subjectName) });
      } else {
          setReviewData({ ...reviewData, subjects: [...currentSubjects, subjectName] });
      }
  };

  const toggleAllowedRoleInReview = (roleName: Role) => {
      const currentAllowed = reviewData.allowedRoles || [];
      if (roleName === reviewData.role) return;
      if (currentAllowed.includes(roleName)) {
          setReviewData({ ...reviewData, allowedRoles: currentAllowed.filter(r => r !== roleName) });
      } else {
          setReviewData({ ...reviewData, allowedRoles: [...currentAllowed, roleName] });
      }
  };

  const handleAddSubject = () => {
      if(newSubject.trim()) {
          dispatch({ type: 'ADD_SYSTEM_SUBJECT', payload: { name: newSubject.trim(), type: newSubjectType } });
          setNewSubject('');
      }
  };

  const handleAddClass = () => {
    if(newClass.trim()) {
        dispatch({ type: 'ADD_SYSTEM_CLASS', payload: newClass.trim() });
        setNewClass('');
    }
  };

  const handleAddSection = (className: string) => {
      if(newSection.trim()) {
          dispatch({ type: 'ADD_CLASS_SECTION', payload: { className, section: newSection.trim() } });
          setNewSection('');
      }
  }

  const handleCreateSession = () => {
      if (!newSessionName.trim()) return;
      dispatch({
          type: 'ADD_EXAM_SESSION',
          payload: {
              id: `es${Date.now()}`,
              name: newSessionName,
              type: newSessionType,
              status: 'open',
              startDate: new Date().toISOString().split('T')[0]
          }
      });
      setNewSessionName('');
  };

  const [resetVal, setResetVal] = useState(1);
  const handleResetReceipt = () => {
      if(window.confirm(`Are you sure you want to reset the receipt counter to ${resetVal}? This is a critical action.`)) {
          dispatch({ type: 'RESET_RECEIPT_COUNTER', payload: Number(resetVal) });
      }
  }

  const handlePublishClassResult = (session: any, published: boolean, reportCount: number) => {
      if (!publishClassId) {
          alert("Please select a class first");
          return;
      }
      if (reportCount === 0) {
          alert("No marks found for this session in the selected class. Teachers must enter marks before you can publish results.");
          return;
      }

      dispatch({
          type: 'PUBLISH_CLASS_RESULT',
          payload: { 
              examSessionId: session.id,
              sessionName: session.name, 
              classId: publishClassId, 
              section: publishSection === '' ? undefined : publishSection, 
              published 
          }
      });
  }

  const selectedClassData = state.systemClasses.find(c => c.name === reviewData.classId);

  // --- ISSUE NOTICES TAB ---
  if (activeTab === 'issue_notices') {
    return (
        <div className="space-y-8 max-w-4xl">
            <div className="bg-white p-8 rounded-2xl border border-galaxy-100 shadow-lg">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 bg-gold-400 rounded-full flex items-center justify-center text-galaxy-900">
                        <Bell size={20} />
                    </div>
                    <div>
                        <h3 className="text-xl font-bold text-galaxy-900">Issue New Notice</h3>
                        <p className="text-sm text-gray-500">Communicate with students, staff, or everyone.</p>
                    </div>
                </div>

                <form onSubmit={handlePostNotice} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="md:col-span-2">
                            <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Notice Title</label>
                            <input 
                                type="text" 
                                required
                                className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-galaxy-500 outline-none transition-all shadow-sm"
                                placeholder="e.g. Winter Break Schedule"
                                value={noticeForm.title}
                                onChange={e => setNoticeForm({...noticeForm, title: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Target Audience</label>
                            <div className="relative">
                                <Users size={16} className="absolute left-3 top-3.5 text-gray-400" />
                                <select 
                                    className="w-full border pl-10 p-3 rounded-xl focus:ring-2 focus:ring-galaxy-500 outline-none transition-all shadow-sm bg-white appearance-none"
                                    value={noticeForm.audience}
                                    onChange={e => setNoticeForm({...noticeForm, audience: e.target.value as any})}
                                >
                                    <option value="all">Everyone</option>
                                    <option value="students">Students Only</option>
                                    <option value="teachers">Staff Only</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Content</label>
                        <textarea 
                            required
                            rows={6}
                            className="w-full border p-4 rounded-xl focus:ring-2 focus:ring-galaxy-500 outline-none transition-all shadow-sm resize-none"
                            placeholder="Type your announcement details here..."
                            value={noticeForm.content}
                            onChange={e => setNoticeForm({...noticeForm, content: e.target.value})}
                        />
                    </div>

                    <div className="flex justify-end">
                        <button 
                            type="submit" 
                            className="bg-galaxy-900 text-white px-8 py-3 rounded-xl hover:bg-galaxy-800 font-bold flex items-center gap-2 shadow-lg shadow-galaxy-900/20 transform transition active:scale-95"
                        >
                            <Send size={18} /> Publish Announcement
                        </button>
                    </div>
                </form>
            </div>

            {/* History Feed */}
            <div className="space-y-4">
                <h4 className="text-sm font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                    <Clock size={16} /> Recently Issued
                </h4>
                {state.notices.length === 0 ? (
                    <div className="p-8 text-center text-gray-400 bg-gray-50 rounded-2xl border border-dashed">
                        No notices have been issued yet.
                    </div>
                ) : (
                    <div className="grid gap-4">
                        {state.notices.slice(0, 5).map(notice => (
                            <div key={notice.id} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm group hover:shadow-md transition-shadow">
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-3">
                                        <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                                            notice.audience === 'all' ? 'bg-gold-100 text-gold-700' :
                                            notice.audience === 'teachers' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'
                                        }`}>
                                            {notice.audience}
                                        </span>
                                        <h5 className="font-bold text-gray-900">{notice.title}</h5>
                                    </div>
                                    <span className="text-xs text-gray-400 font-mono">{notice.date}</span>
                                </div>
                                <p className="text-sm text-gray-600 line-clamp-2 mb-4 leading-relaxed">
                                    {notice.content}
                                </p>
                                <div className="flex justify-between items-center text-[10px] text-gray-400 border-t pt-3">
                                    <span className="flex items-center gap-1">
                                        <LogIn size={12} className="opacity-50" /> Posted By: <strong className="text-gray-500">{notice.postedBy}</strong>
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
  }

  // --- IMPERSONATION LOGIC ---
  if (activeTab === 'impersonate' && role === 'developer') {
    if (viewMode === 'roles') {
        const roles: { id: Role, label: string, icon: any, color: string }[] = [
            { id: 'admin', label: 'Admin', icon: Shield, color: 'bg-red-100 text-red-700' },
            { id: 'teacher', label: 'Teacher', icon: BookOpen, color: 'bg-purple-100 text-purple-700' },
            { id: 'student', label: 'Student', icon: GraduationCap, color: 'bg-blue-100 text-blue-700' },
            { id: 'accountant', label: 'Accountant', icon: Calculator, color: 'bg-green-100 text-green-700' },
            { id: 'intern', label: 'Intern', icon: Briefcase, color: 'bg-teal-100 text-teal-700' },
        ];

        return (
            <div className="space-y-6">
                <h3 className="text-xl font-bold flex items-center gap-2">
                    <ScanFace className="text-galaxy-600" /> Act As User
                </h3>
                <p className="text-gray-500 text-sm">
                    Select a role to see available users. You can switch to their view without logging out.
                </p>
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6">
                    {roles.map((r) => (
                        <button 
                            key={r.id}
                            onClick={() => { setSelectedRoleForImp(r.id); setViewMode('users'); setImpSearch(''); }}
                            className="flex flex-col items-center justify-center p-6 bg-white border rounded-xl shadow-sm hover:shadow-md transition-all hover:-translate-y-1"
                        >
                            <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${r.color}`}>
                                <r.icon size={32} />
                            </div>
                            <span className="font-bold text-gray-800">{r.label}</span>
                        </button>
                    ))}
                </div>
            </div>
        )
    }
    const filteredUsers = state.users.filter(u => {
        if (u.id === currentUser?.id) return false;
        const matchesRole = u.role === selectedRoleForImp;
        const searchLower = impSearch.toLowerCase();
        const matchesSearch = u.name.toLowerCase().includes(searchLower) || u.email.toLowerCase().includes(searchLower);
        return matchesRole && matchesSearch;
    });

    const handleImpersonate = (user: User) => {
        // Confirmation alert removed as requested.
        dispatch({ type: 'IMPERSONATE_USER', payload: user });
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center gap-4 mb-6">
                <button onClick={() => setViewMode('roles')} className="p-2 rounded-full hover:bg-gray-200 transition-colors"><ChevronLeft size={24} /></button>
                <div><h3 className="text-xl font-bold">Select User</h3></div>
            </div>
            <div className="bg-white p-4 rounded-xl shadow-sm border">
                <div className="relative">
                    <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
                    <input type="text" placeholder={`Search ${selectedRoleForImp}...`} className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none" value={impSearch} onChange={(e) => setImpSearch(e.target.value)} autoFocus />
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredUsers.map(user => (
                    <div key={user.id} className="bg-white p-4 rounded-xl border hover:shadow-md transition-shadow">
                        <div className="flex justify-between items-start mb-2">
                            <div><h4 className="font-bold text-gray-800">{user.name}</h4><p className="text-xs text-gray-500">{user.email}</p></div>
                        </div>
                        <button onClick={() => handleImpersonate(user)} className="w-full bg-galaxy-900 text-white py-2 rounded-lg hover:bg-galaxy-700 mt-2 text-sm">Act as {user.name.split(' ')[0]}</button>
                    </div>
                ))}
            </div>
        </div>
    )
  }

  // --- Registration / User Management ---
  if (activeTab === 'registration' || activeTab === 'users') {
      const usersToManage = state.users
        .filter(u => u.status === 'active' && u.id !== currentUser?.id)
        .filter(u => {
            if (currentUser?.role === 'developer') return true;
            const myLevel = roleHierarchy[currentUser?.role || 'guest'];
            const targetLevel = roleHierarchy[u.role || 'guest'];
            return myLevel > targetLevel;
        })
        .filter(u => {
            const matchesSearch = u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                                  u.email.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesRole = filterRole === 'all' || u.role === filterRole;
            return matchesSearch && matchesRole;
        });

      return (
          <div className="space-y-8">
              <div className="bg-white p-6 rounded-xl border border-galaxy-200 shadow-sm">
                  <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                      <UserCheck className="text-galaxy-600" /> Pending Approvals
                  </h3>
                  {getPendingUsers().length === 0 ? (
                      <p className="text-gray-500 italic">No pending registration requests requiring your approval.</p>
                  ) : (
                      <div className="grid gap-4">
                          {getPendingUsers().map(u => (
                              <div key={u.id} className="flex items-center justify-between border p-4 rounded-lg bg-yellow-50 border-yellow-100">
                                  <div>
                                      <p className="font-bold text-gray-800">{u.name}</p>
                                      <p className="text-sm text-gray-600">{u.role.toUpperCase()} • {u.email}</p>
                                      <p className="text-xs text-gray-500">Applied: {new Date().toLocaleDateString()}</p>
                                  </div>
                                  <div className="flex gap-2">
                                      <button onClick={() => handleReject(u.id)} className="px-3 py-1 bg-white border border-red-200 text-red-600 rounded hover:bg-red-50 text-sm">Reject</button>
                                      <button onClick={() => openReviewModal(u)} className="px-3 py-1 bg-galaxy-600 text-white rounded hover:bg-galaxy-700 text-sm flex items-center gap-1">
                                          <Eye size={14} /> Review
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  )}
              </div>

              {showSubjectManager && (
                  <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                      <div className="bg-white rounded-xl shadow-xl max-md w-full">
                          <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl">
                              <h3 className="font-bold">Subject Library</h3>
                              <button onClick={() => setShowSubjectManager(false)}><X size={18} /></button>
                          </div>
                          <div className="p-6">
                              <div className="flex gap-2 mb-4">
                                  <input type="text" placeholder="Subject Name" className="flex-1 border p-2 rounded" value={newSubject} onChange={e => setNewSubject(e.target.value)} />
                                  <select className="border p-2 rounded" value={newSubjectType} onChange={e => setNewSubjectType(e.target.value as SubjectType)}>
                                      <option value="Theory">Theory</option><option value="Practical">Practical</option>
                                  </select>
                                  <button onClick={handleAddSubject} className="bg-green-600 text-white px-3 py-2 rounded"><Plus size={18} /></button>
                              </div>
                              <div className="max-h-60 overflow-y-auto space-y-2">
                                  {state.availableSubjects.map(s => (
                                      <div key={s.name} className="flex justify-between items-center p-2 bg-gray-50 rounded border">
                                          <span>{s.name} <span className="text-xs text-gray-400">({s.type})</span></span>
                                          <button onClick={() => dispatch({ type: 'DELETE_SYSTEM_SUBJECT', payload: s.name })} className="text-red-500 hover:text-red-700"><Trash2 size={16} /></button>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  </div>
              )}

              {showClassManager && (
                  <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full">
                          <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-xl">
                              <h3 className="font-bold">Class & Section Library</h3>
                              <button onClick={() => setShowClassManager(false)}><X size={18} /></button>
                          </div>
                          <div className="p-6">
                              <div className="flex gap-2 mb-6">
                                  <input type="text" placeholder="New Class (e.g. 11)" className="flex-1 border p-2 rounded" value={newClass} onChange={e => setNewClass(e.target.value)} />
                                  <button onClick={handleAddClass} className="bg-green-600 text-white px-3 py-2 rounded flex items-center gap-1"><Plus size={16} /> Add Class</button>
                              </div>
                              <div className="max-h-96 overflow-y-auto space-y-4">
                                  {state.systemClasses.map(c => (
                                      <div key={c.name} className="border rounded-lg overflow-hidden">
                                          <div className="bg-gray-100 p-3 flex justify-between items-center font-bold"><span>{c.name}</span><button onClick={() => dispatch({ type: 'DELETE_SYSTEM_CLASS', payload: c.name })} className="text-red-500 hover:text-red-700 p-1"><Trash2 size={16} /></button></div>
                                          <div className="p-3 bg-white">
                                              <div className="flex flex-wrap gap-2 mb-2">{c.sections.map(sec => (<div key={sec} className="bg-blue-50 text-blue-800 text-xs px-2 py-1 rounded border border-blue-200 flex items-center gap-1">{sec}<button onClick={() => dispatch({ type: 'DELETE_CLASS_SECTION', payload: { className: c.name, section: sec } })} className="text-red-400 hover:text-red-600"><X size={12} /></button></div>))}</div>
                                              <div className="flex gap-2 mt-2">
                                                  <input type="text" placeholder={`Add section to ${c.name}`} className="flex-1 border p-1 rounded text-sm" value={activeClassForSection === c.name ? newSection : ''} onChange={e => { setActiveClassForSection(c.name); setNewSection(e.target.value); }} />
                                                  <button onClick={() => { setActiveClassForSection(c.name); handleAddSection(c.name); }} className="bg-blue-600 text-white px-2 py-1 rounded text-xs">Add</button>
                                              </div>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  </div>
              )}

              {reviewUser && (
                  <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full overflow-hidden max-h-[90vh] overflow-y-auto">
                          <div className="bg-galaxy-900 text-white p-4 flex justify-between items-center sticky top-0 z-10">
                              <h3 className="font-bold">
                                  {reviewUser.status === 'pending' ? 'Review Application' : 'Edit User Details'}
                              </h3>
                              <button onClick={() => setReviewUser(null)}><X size={20} /></button>
                          </div>
                          <div className="p-6 space-y-4">
                              <div className="grid grid-cols-2 gap-4 text-sm">
                                  <div>
                                      <label className="block text-xs font-bold text-gray-500 uppercase">Full Name</label>
                                      <input 
                                          type="text" 
                                          value={reviewData.name || ''}
                                          onChange={e => setReviewData({...reviewData, name: e.target.value})}
                                          className="w-full border p-2 rounded mt-1 outline-none"
                                      />
                                  </div>
                                  <div>
                                      <label className="block text-xs font-bold text-gray-500 uppercase">Primary Role</label>
                                      <select 
                                          value={reviewData.role || 'student'}
                                          onChange={e => setReviewData({...reviewData, role: e.target.value as any})}
                                          className="w-full border p-2 rounded mt-1 bg-white outline-none"
                                      >
                                          <option value="student">Student</option>
                                          <option value="intern">Intern</option>
                                          <option value="teacher">Teacher</option>
                                          <option value="accountant">Accountant</option>
                                          <option value="admin">Admin</option>
                                      </select>
                                  </div>
                                  <div className="col-span-2">
                                      <label className="block text-xs font-bold text-gray-500 uppercase">Email</label>
                                      <input 
                                          type="email" 
                                          value={reviewData.email || ''}
                                          onChange={e => setReviewData({...reviewData, email: e.target.value})}
                                          className="w-full border p-2 rounded mt-1 outline-none"
                                      />
                                  </div>
                              </div>

                              <div className="bg-gray-50 p-3 rounded-lg border">
                                  <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Allowed Roles (Access Control)</label>
                                  <div className="flex flex-wrap gap-2">
                                      {(['admin', 'teacher', 'accountant', 'student', 'intern'] as Role[]).map(r => {
                                          const isPrimary = reviewData.role === r;
